// ServiceIdentity represents an authenticated service in the mesh
type ServiceIdentity struct {
	ServiceName string
	Namespace   string
	ClusterID   string
	IssuedAt    time.Time
	ExpiresAt   time.Time
}

// TokenValidator validates service mesh tokens
type TokenValidator struct {
	secretKey       []byte
	trustedServices map[string]bool
}

func NewTokenValidator(secret string, trustedServices []string) *TokenValidator {
	trusted := make(map[string]bool)
	for _, s := range trustedServices {
		trusted[s] = true
	}
	return &TokenValidator{
		secretKey:       []byte(secret),
		trustedServices: trusted,
	}
}

// GenerateToken creates a signed token for a service
func (tv *TokenValidator) GenerateToken(serviceName, namespace, clusterID string) string {
	now := time.Now()
	expires := now.Add(tokenExpiration)
	payload := fmt.Sprintf("%s|%s|%s|%d|%d", serviceName, namespace, clusterID, now.Unix(), expires.Unix())
	mac := hmac.New(sha256.New, tv.secretKey)
	mac.Write([]byte(payload))
	signature := hex.EncodeToString(mac.Sum(nil))
	return fmt.Sprintf("%s.%s", payload, signature)
}

// ValidateToken validates a token and returns the service identity
func (tv *TokenValidator) ValidateToken(token string) (*ServiceIdentity, error) {
	parts := strings.SplitN(token, ".", 2)
	if len(parts) != 2 {
		return nil, fmt.Errorf("invalid token format")
	}

	payload := parts[0]
	providedSig := parts[1]

	// Verify signature
	mac := hmac.New(sha256.New, tv.secretKey)
	mac.Write([]byte(payload))
	expectedSig := hex.EncodeToString(mac.Sum(nil))

	if !hmac.Equal([]byte(providedSig), []byte(expectedSig)) {
		return nil, fmt.Errorf("invalid token signature")
	}

	// Parse payload
	fields := strings.Split(payload, "|")
	if len(fields) != 5 {
		return nil, fmt.Errorf("invalid token payload")
	}

	var issuedAt, expiresAt int64
	fmt.Sscanf(fields[3], "%d", &issuedAt)
	fmt.Sscanf(fields[4], "%d", &expiresAt)

	identity := &ServiceIdentity{
		ServiceName: fields[0],
		Namespace:   fields[1],
		ClusterID:   fields[2],
		IssuedAt:    time.Unix(issuedAt, 0),
		ExpiresAt:   time.Unix(expiresAt, 0),
	}

	// Check expiration
	if time.Now().After(identity.ExpiresAt) {
		return nil, fmt.Errorf("token expired")
	}

	// Check if service is trusted
	if !tv.trustedServices[identity.ServiceName] {
		return nil, fmt.Errorf("service %q is not trusted", identity.ServiceName)
	}

	return identity, nil
}

