// authenticate extracts and validates the token from gRPC metadata
func authenticate(ctx context.Context, validator *TokenValidator) (*ServiceIdentity, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Error(codes.Unauthenticated, "no metadata provided")
	}

	// Extract authorization token
	authValues := md.Get(tokenHeader)
	if len(authValues) == 0 {
		return nil, status.Error(codes.Unauthenticated, "no authorization token provided")
	}

	token := authValues[0]
	if strings.HasPrefix(token, tokenPrefix) {
		token = strings.TrimPrefix(token, tokenPrefix)
	}

	if token == "" {
		return nil, status.Error(codes.Unauthenticated, "empty authorization token")
	}

	// Validate the token
	identity, err := validator.ValidateToken(token)
	if err != nil {
		return nil, status.Errorf(codes.Unauthenticated, "token validation failed: %v", err)
	}

	// Optionally verify service name header matches token
	serviceNames := md.Get(serviceNameHeader)
	if len(serviceNames) > 0 && serviceNames[0] != identity.ServiceName {
		return nil, status.Error(codes.Unauthenticated, "service name mismatch")
	}

	// Log request ID if present
	requestIDs := md.Get(requestIDHeader)
	if len(requestIDs) > 0 {
		log.Printf("Request ID: %s from service: %s", requestIDs[0], identity.ServiceName)
	}

	return identity, nil
}

