// --------- Authorization Interceptor ---------

// RBACPolicy defines role-based access control for service mesh
type RBACPolicy struct {
	// method -> allowed services
	rules map[string]map[string]bool
}

func NewRBACPolicy() *RBACPolicy {
	return &RBACPolicy{
		rules: map[string]map[string]bool{
			"/mesh.MeshService/GetData": {
				"api-gateway":       true,
				"worker-service":    true,
				"analytics-service": true,
			},
			"/mesh.MeshService/GetServiceInfo": {
				"api-gateway":       true,
				"service-discovery": true,
				"monitoring":        true,
			},
		},
	}
}

func (p *RBACPolicy) IsAllowed(method string, serviceName string) bool {
	allowedServices, exists := p.rules[method]
	if !exists {
		// If no rule exists, deny by default
		return false
	}
	return allowedServices[serviceName]
}

// UnaryRBACInterceptor creates a unary interceptor for RBAC
func UnaryRBACInterceptor(policy *RBACPolicy) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		// Skip RBAC for health check
		if info.FullMethod == "/mesh.MeshService/HealthCheck" {
			return handler(ctx, req)
		}

		identity, ok := GetServiceIdentity(ctx)
		if !ok {
			return nil, status.Error(codes.Internal, "no service identity in context")
		}

		if !policy.IsAllowed(info.FullMethod, identity.ServiceName) {
			log.Printf("RBAC denied: service=%s method=%s", identity.ServiceName, info.FullMethod)
			return nil, status.Errorf(codes.PermissionDenied,
				"service %q is not authorized for method %s", identity.ServiceName, info.FullMethod)
		}

		return handler(ctx, req)
	}
}

// --------- Logging Interceptor ---------

func UnaryLoggingInterceptor() grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		start := time.Now()
		resp, err := handler(ctx, req)
		duration := time.Since(start)

		statusCode := codes.OK
		if err != nil {
			statusCode = status.Code(err)
		}

		identity, _ := GetServiceIdentity(ctx)
		serviceName := "unknown"
		if identity != nil {
			serviceName = identity.ServiceName
		}

		log.Printf("gRPC call: method=%s caller=%s status=%s duration=%v",
			info.FullMethod, serviceName, statusCode, duration)

		return resp, err
	}
}

// --------- Chain Interceptors Helper ---------

func chainUnaryInterceptors(interceptors ...grpc.UnaryServerInterceptor) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		chain := handler
		for i := len(interceptors) - 1; i >= 0; i-- {
			interceptor := interceptors[i]
			next := chain
			chain = func(ctx context.Context, req interface{}) (interface{}, error) {
				return interceptor(ctx, req, info, next)
			}
		}
		return chain(ctx, req)
	}
}

